722:         if (inheritErrorHandler == null || inheritErrorHandler) {
723:             LOG.trace("{} is configured to inheritErrorHandler", definition);
724:             Processor output = channel.getOutput();
725:             Processor errorHandler = wrapInErrorHandler(output);
726:             // set error handler on channel
727:             channel.setErrorHandler(errorHandler);
728:         } else {
